        "AWS::AppConfig::DeploymentStrategy": {
                description: "Resource Type definition for AWS::AppConfig::DeploymentStrategy",
                attributes: ["Id"],
                properties: {
                        DeploymentDurationInMinutes: {
                                type: "number",
                                required: true,
                                description: "Total amount of time for a deployment to last.",
                        },
                        Description: {
                                type: "string",
                                required: false,
                                description: "A description of the deployment strategy.",
                        },
                        FinalBakeTimeInMinutes: {
                                type: "number",
                                required: false,
                                description:
                                        "Specifies the amount of time AWS AppConfig monitors for Amazon CloudWatch alarms after the configuration has been deployed to 100% of its targets, before considering the deployment to be complete. If an alarm is triggered during this time, AWS AppConfig rolls back the deployment. You must configure permissions for AWS AppConfig to roll back based on CloudWatch alarms. For more information, see Configuring permissions for rollback based on Amazon CloudWatch alarms in the AWS AppConfig User Guide.",
                        },
                        GrowthFactor: {
                                type: "number",
                                required: true,
                                description:
                                        "The percentage of targets to receive a deployed configuration during each interval.",
                        },
                        GrowthType: {
                                type: "string",
                                required: false,
                                description:
                                        "The algorithm used to define how percentage grows over time. AWS AppConfig supports the following growth types:\n\nLinear: For this type, AWS AppConfig processes the deployment by dividing the total number of targets by the value specified for Step percentage. For example, a linear deployment that uses a Step percentage of 10 deploys the configuration to 10 percent of the hosts. After those deployments are complete, the system deploys the configuration to the next 10 percent. This continues until 100% of the targets have successfully received the configuration.\n\nExponential: For this type, AWS AppConfig processes the deployment exponentially using the following formula: G*(2^N). In this formula, G is the growth factor specified by the user and N is the number of steps until the configuration is deployed to all targets. For example, if you specify a growth factor of 2, then the system rolls out the configuration as follows:\n\n2*(2^0)\n\n2*(2^1)\n\n2*(2^2)\n\nExpressed numerically, the deployment rolls out as follows: 2% of the targets, 4% of the targets, 8% of the targets, and continues until the configuration has been deployed to all targets.",
                        },
                        Name: {
                                type: "string",
                                required: true,
                                description: "A name for the deployment strategy.",
                        },
                        ReplicateTo: {
                                type: "string",
                                required: true,
                                description:
                                        "Save the deployment strategy to a Systems Manager (SSM) document.",
                        },
                        Tags: {
                                type: "array",
                                required: false,
                                description:
                                        "Assigns metadata to an AWS AppConfig resource. Tags help organize and categorize your AWS AppConfig resources. Each tag consists of a key and an optional value, both of which you define. You can specify a maximum of 50 tags for a resource.",
                        },
                        Id: {
                                type: "string",
                                required: false,
                                description: "The deployment strategy ID.",
                        },
                },
        },
