        "AWS::Backup::Framework": {
                description:
                        "Contains detailed information about a framework. Frameworks contain controls, which evaluate and report on your backup events and resources. Frameworks generate daily compliance results.",
                attributes: [
                        "FrameworkArn",
                        "CreationTime",
                        "FrameworkStatus",
                        "DeploymentStatus",
                ],
                properties: {
                        FrameworkName: {
                                type: "string",
                                required: false,
                                description:
                                        "The unique name of a framework. This name is between 1 and 256 characters, starting with a letter, and consisting of letters (a-z, A-Z), numbers (0-9), and underscores (_).",
                        },
                        FrameworkDescription: {
                                type: "string",
                                required: false,
                                description:
                                        "An optional description of the framework with a maximum 1,024 characters.",
                        },
                        FrameworkArn: {
                                type: "string",
                                required: false,
                                description:
                                        "An Amazon Resource Name (ARN) that uniquely identifies Framework as a resource",
                        },
                        DeploymentStatus: {
                                type: "string",
                                required: false,
                                description:
                                        "The deployment status of a framework. The statuses are: 'CREATE_IN_PROGRESS | UPDATE_IN_PROGRESS | DELETE_IN_PROGRESS | COMPLETED | FAILED'",
                        },
                        CreationTime: {
                                type: "string",
                                required: false,
                                description:
                                        "The date and time that a framework is created, in ISO 8601 representation. The value of CreationTime is accurate to milliseconds. For example, 2020-07-10T15:00:00.000-08:00 represents the 10th of July 2020 at 3:00 PM 8 hours behind UTC.",
                        },
                        FrameworkControls: {
                                type: "array",
                                required: true,
                                description:
                                        "Contains detailed information about all of the controls of a framework. Each framework must contain at least one control.",
                        },
                        FrameworkStatus: {
                                type: "string",
                                required: false,
                                description:
                                        "A framework consists of one or more controls. Each control governs a resource, such as backup plans, backup selections, backup vaults, or recovery points. You can also turn AWS Config recording on or off for each resource. The statuses are:\n\n'ACTIVE' when recording is turned on for all resources governed by the framework.\n\n'PARTIALLY_ACTIVE' when recording is turned off for at least one resource governed by the framework.\n\n'INACTIVE' when recording is turned off for all resources governed by the framework.\n\n'UNAVAILABLE' when AWS Backup is unable to validate recording status at this time.",
                        },
                        FrameworkTags: {
                                type: "array",
                                required: false,
                                description:
                                        "Metadata that you can assign to help organize the frameworks that you create. Each tag is a key-value pair.",
                        },
                },
        },
