        "AWS::CloudFront::OriginAccessControl": {
                description:
                        "Creates a new origin access control in CloudFront. After you create an origin access control, you can add it to an origin in a CloudFront distribution so that CloudFront sends authenticated (signed) requests to the origin.\n This makes it possible to block public access to the origin, allowing viewers (users) to access the origin's content only through CloudFront.\n For more information about using a CloudFront origin access control, see [Restricting access to an origin](https://docs.aws.amazon.com/AmazonCloudFront/latest/DeveloperGuide/private-content-restricting-access-to-origin.html) in the *Amazon CloudFront Developer Guide*.",
                attributes: ["Id"],
                properties: {
                        Id: { type: "string", required: false, description: "" },
                        OriginAccessControlConfig: {
                                type: "object",
                                required: true,
                                description: "The origin access control.",
                        },
                },
        },
        "AWS::CloudFront::OriginRequestPolicy": {
                description:
                        "An origin request policy.\n When it's attached to a cache behavior, the origin request policy determines the values that CloudFront includes in requests that it sends to the origin. Each request that CloudFront sends to the origin includes the following:\n  +  The request body and the URL path (without the domain name) from the viewer request.\n  +  The headers that CloudFront automatically includes in every origin request, including ''Host'', ''User-Agent'', and ''X-Amz-Cf-Id''.\n  +  All HTTP headers, cookies, and URL query strings that are specified in the cache policy or the origin request policy. These can include items from the viewer request and, in the case of headers, additional ones that are added by CloudFront.\n  \n CloudFront sends a request when it can't find an object in its cache that matches the request. If you want to send values to the origin and also include them in the cache key, use ''CachePolicy''.",
                attributes: ["Id", "LastModifiedTime"],
                properties: {
                        Id: { type: "string", required: false, description: "" },
                        LastModifiedTime: { type: "string", required: false, description: "" },
                        OriginRequestPolicyConfig: {
                                type: "object",
                                required: true,
                                description: "The origin request policy configuration.",
                        },
                },
        },
        "AWS::CloudFront::PublicKey": {
                description:
                        "A public key that you can use with [signed URLs and signed cookies](https://docs.aws.amazon.com/AmazonCloudFront/latest/DeveloperGuide/PrivateContent.html), or with [field-level encryption](https://docs.aws.amazon.com/AmazonCloudFront/latest/DeveloperGuide/field-level-encryption.html).\n CloudFront supports signed URLs and signed cookies with RSA 2048 or ECDSA 256 key signatures. Field-level encryption is only compatible with RSA 2048 key signatures.",
                attributes: ["Id", "CreatedTime"],
                properties: {
                        CreatedTime: { type: "string", required: false, description: "" },
                        Id: { type: "string", required: false, description: "" },
                        PublicKeyConfig: {
                                type: "object",
                                required: true,
                                description:
                                        "Configuration information about a public key that you can use with [signed URLs and signed cookies](https://docs.aws.amazon.com/AmazonCloudFront/latest/DeveloperGuide/PrivateContent.html), or with [field-level encryption](https://docs.aws.amazon.com/AmazonCloudFront/latest/DeveloperGuide/field-level-encryption.html).",
                        },
                },
        },
