        "AWS::EC2::KeyPair": {
                description:
                        "Specifies a key pair for use with an EC2long instance as follows:\n  +  To import an existing key pair, include the ''PublicKeyMaterial'' property.\n  +  To create a new key pair, omit the ''PublicKeyMaterial'' property.\n  \n When you import an existing key pair, you specify the public key material for the key. We assume that you have the private key material for the key. CFNlong does not create or return the private key material when you import a key pair.\n When you create a new key pair, the private key is saved to SYSlong Parameter Store, using a parameter with the following name: ''/ec2/keypair/{key_pair_id}''. For more information about retrieving private key, and the required permissions, see [Create a key pair using](https://docs.aws.amazon.com/AWSEC2/latest/UserGuide/create-key-pairs.html#create-key-pair-cloudformation) in the *User Guide*.\n When CFN deletes a key pair that was created or imported by a stack, it also deletes the parameter that was used to store the private key material in Parameter Store.",
                attributes: ["KeyPairId", "KeyFingerprint"],
                properties: {
                        KeyName: {
                                type: "string",
                                required: true,
                                description:
                                        "A unique name for the key pair.\n Constraints: Up to 255 ASCII characters",
                        },
                        KeyType: {
                                type: "string",
                                required: false,
                                description:
                                        "The type of key pair. Note that ED25519 keys are not supported for Windows instances.\n If the ''PublicKeyMaterial'' property is specified, the ''KeyType'' property is ignored, and the key type is inferred from the ''PublicKeyMaterial'' value.\n Default: ''rsa''",
                        },
                        KeyFormat: {
                                type: "string",
                                required: false,
                                description: "The format of the key pair.\n Default: ''pem''",
                        },
                        PublicKeyMaterial: {
                                type: "string",
                                required: false,
                                description:
                                        "The public key material. The ''PublicKeyMaterial'' property is used to import a key pair. If this property is not specified, then a new key pair will be created.",
                        },
                        KeyFingerprint: { type: "string", required: false, description: "" },
                        KeyPairId: { type: "string", required: false, description: "" },
                        Tags: {
                                type: "array",
                                required: false,
                                description: "The tags to apply to the key pair.",
                        },
                },
        },
        "AWS::EC2::LaunchTemplate": {
                description:
                        "Specifies the properties for creating a launch template.\n The minimum required properties for specifying a launch template are as follows:\n  +  You must specify at least one property for the launch template data.\n  +  You can optionally specify a name for the launch template. If you do not specify a name, CFN creates a name for you.\n  \n A launch template can contain some or all of the configuration information to launch an instance. When you launch an instance using a launch template, instance properties that are not specified in the launch template use default values, except the ''ImageId'' property, which has no default value. If you do not specify an AMI ID for the launch template ''ImageId'' property, you must specify an AMI ID for the instance ''ImageId'' property.\n For more information, see [Launch an instance from a launch template](https://docs.aws.amazon.com/AWSEC2/latest/UserGuide/ec2-launch-templates.html) in the *Amazon EC2 User Guide*.",
                attributes: [
                        "DefaultVersionNumber",
                        "LaunchTemplateId",
                        "LatestVersionNumber",
                ],
                properties: {
                        LaunchTemplateName: {
                                type: "string",
                                required: false,
                                description: "A name for the launch template.",
                        },
                        LaunchTemplateData: {
                                type: "object",
                                required: true,
                                description: "The information for the launch template.",
                        },
                        VersionDescription: {
                                type: "string",
                                required: false,
                                description:
                                        "A description for the first version of the launch template.",
                        },
                        TagSpecifications: {
                                type: "array",
                                required: false,
                                description:
                                        "The tags to apply to the launch template on creation. To tag the launch template, the resource type must be ''launch-template''.\n To specify the tags for resources that are created during instance launch, use [TagSpecifications](https://docs.aws.amazon.com/AWSCloudFormation/latest/UserGuide/aws-properties-ec2-launchtemplate-launchtemplatedata.html#cfn-ec2-launchtemplate-launchtemplatedata-tagspecifications).",
                        },
                        LatestVersionNumber: {
                                type: "string",
                                required: false,
                                description: "",
                        },
                        LaunchTemplateId: { type: "string", required: false, description: "" },
                        DefaultVersionNumber: {
                                type: "string",
                                required: false,
                                description: "",
                        },
                },
        },
