        "AWS::EC2::NetworkAclEntry": {
                description: "Resource Type definition for AWS::EC2::NetworkAclEntry",
                attributes: ["Id"],
                properties: {
                        PortRange: {
                                type: "object",
                                required: false,
                                description:
                                        "The IPv4 network range to allow or deny, in CIDR notation (for example 172.16.0.0/24). We modify the specified CIDR block to its canonical form; for example, if you specify 100.68.0.18/18, we modify it to 100.68.0.0/18",
                        },
                        NetworkAclId: {
                                type: "string",
                                required: true,
                                description: "The ID of the network ACL",
                        },
                        RuleAction: {
                                type: "string",
                                required: true,
                                description:
                                        "Indicates whether to allow or deny the traffic that matches the rule",
                        },
                        CidrBlock: {
                                type: "string",
                                required: false,
                                description:
                                        "The IPv4 CIDR range to allow or deny, in CIDR notation (for example, 172.16.0.0/24). Requirement is conditional: You must specify the CidrBlock or Ipv6CidrBlock property",
                        },
                        Egress: {
                                type: "boolean",
                                required: false,
                                description:
                                        "Indicates whether this is an egress rule (rule is applied to traffic leaving the subnet)",
                        },
                        RuleNumber: {
                                type: "integer",
                                required: true,
                                description:
                                        "Rule number to assign to the entry, such as 100. ACL entries are processed in ascending order by rule number. Entries can't use the same rule number unless one is an egress rule and the other is an ingress rule",
                        },
                        Id: { type: "string", required: false, description: "" },
                        Ipv6CidrBlock: {
                                type: "string",
                                required: false,
                                description:
                                        "The IPv6 network range to allow or deny, in CIDR notation (for example 2001:db8:1234:1a00::/64)",
                        },
                        Protocol: {
                                type: "integer",
                                required: true,
                                description:
                                        'The protocol number. A value of "-1" means all protocols. If you specify "-1" or a protocol number other than "6" (TCP), "17" (UDP), or "1" (ICMP), traffic on all ports is allowed, regardless of any ports or ICMP types or codes that you specify. If you specify protocol "58" (ICMPv6) and specify an IPv4 CIDR block, traffic for all ICMP types and codes allowed, regardless of any that you specify. If you specify protocol "58" (ICMPv6) and specify an IPv6 CIDR block, you must specify an ICMP type and code',
                        },
                        Icmp: {
                                type: "object",
                                required: false,
                                description:
                                        "The Internet Control Message Protocol (ICMP) code and type. Requirement is conditional: Required if specifying 1 (ICMP) for the protocol parameter",
                        },
                },
        },
