        "AWS::EC2::VPCEndpoint": {
                description:
                        "Specifies a VPC endpoint. A VPC endpoint provides a private connection between your VPC and an endpoint service. You can use an endpoint service provided by AWS, an MKT Partner, or another AWS accounts in your organization. For more information, see the [User Guide](https://docs.aws.amazon.com/vpc/latest/privatelink/).\n An endpoint of type ''Interface'' establishes connections between the subnets in your VPC and an AWS-service, your own service, or a service hosted by another AWS-account. With an interface VPC endpoint, you specify the subnets in which to create the endpoint and the security groups to associate with the endpoint network interfaces.\n An endpoint of type ''gateway'' serves as a target for a route in your route table for traffic destined for S3 or DDB. You can specify an endpoint policy for the endpoint, which controls access to the service from your VPC. You can also specify the VPC route tables that use the endpoint. For more information about connectivity to S3, see [Why can't I connect to an S3 bucket using a gateway VPC endpoint?](https://docs.aws.amazon.com/premiumsupport/knowledge-center/connect-s3-vpc-endpoint)\n An endpoint of type ''GatewayLoadBalancer'' provides private connectivity between your VPC and virtual appliances from a service provider.",
                attributes: ["NetworkInterfaceIds", "CreationTimestamp", "DnsEntries", "Id"],
                properties: {
                        PrivateDnsEnabled: {
                                type: "boolean",
                                required: false,
                                description:
                                        "Indicate whether to associate a private hosted zone with the specified VPC. The private hosted zone contains a record set for the default public DNS name for the service for the Region (for example, ''kinesis.us-east-1.amazonaws.com''), which resolves to the private IP addresses of the endpoint network interfaces in the VPC. This enables you to make requests to the default public DNS name for the service instead of the public DNS names that are automatically generated by the VPC endpoint service.\n To use a private hosted zone, you must set the following VPC attributes to ''true'': ''enableDnsHostnames'' and ''enableDnsSupport''.\n This property is supported only for interface endpoints.\n Default: ''false''",
                        },
                        IpAddressType: {
                                type: "string",
                                required: false,
                                description: "The supported IP address types.",
                        },
                        ServiceRegion: {
                                type: "string",
                                required: false,
                                description: "Describes a Region.",
                        },
                        CreationTimestamp: {
                                type: "string",
                                required: false,
                                description: "",
                        },
                        DnsOptions: {
                                type: "object",
                                required: false,
                                description: "Describes the DNS options for an endpoint.",
                        },
                        NetworkInterfaceIds: {
                                type: "array",
                                required: false,
                                description: "",
                        },
                        DnsEntries: { type: "array", required: false, description: "" },
                        ResourceConfigurationArn: {
                                type: "string",
                                required: false,
                                description:
                                        "The Amazon Resource Name (ARN) of the resource configuration.",
                        },
                        SecurityGroupIds: {
                                type: "array",
                                required: false,
                                description:
                                        "The IDs of the security groups to associate with the endpoint network interfaces. If this parameter is not specified, we use the default security group for the VPC. Security groups are supported only for interface endpoints.",
                        },
                        SubnetIds: {
                                type: "array",
                                required: false,
                                description:
                                        "The IDs of the subnets in which to create endpoint network interfaces. You must specify this property for an interface endpoint or a Gateway Load Balancer endpoint. You can't specify this property for a gateway endpoint. For a Gateway Load Balancer endpoint, you can specify only one subnet.",
                        },
                        ServiceNetworkArn: {
                                type: "string",
                                required: false,
                                description:
                                        "The Amazon Resource Name (ARN) of the service network.",
                        },
                        VpcId: {
                                type: "string",
                                required: true,
                                description: "The ID of the VPC.",
                        },
                        RouteTableIds: {
                                type: "array",
                                required: false,
                                description:
                                        "The IDs of the route tables. Routing is supported only for gateway endpoints.",
                        },
                        ServiceName: {
                                type: "string",
                                required: false,
                                description: "The name of the endpoint service.",
                        },
                        PolicyDocument: {
                                type: "string",
                                required: false,
                                description:
                                        'An endpoint policy, which controls access to the service from the VPC. The default endpoint policy allows full access to the service. Endpoint policies are supported only for gateway and interface endpoints.\n For CloudFormation templates in YAML, you can provide the policy in JSON or YAML format. For example, if you have a JSON policy, you can convert it to YAML before including it in the YAML template, and CFNlong converts the policy to JSON format before calling the API actions for privatelink. Alternatively, you can include the JSON directly in the YAML, as shown in the following \'\'Properties\'\' section:\n \'\'Properties: VpcEndpointType: \'Interface\' ServiceName: !Sub \'com.amazonaws.${AWS::Region}.logs\' PolicyDocument: \'{ "Version":"2012-10-17", "Statement": [{ "Effect":"Allow", "Principal":"*", "Action":["logs:Describe*","logs:Get*","logs:List*","logs:FilterLogEvents"], "Resource":"*" }] }\'\'\'',
                        },
                        VpcEndpointType: {
                                type: "string",
                                required: false,
                                description: "The type of endpoint.\n Default: Gateway",
                        },
                        Id: { type: "string", required: false, description: "" },
                        Tags: {
                                type: "array",
                                required: false,
                                description: "The tags to associate with the endpoint.",
                        },
                },
        },
