        "AWS::SecurityHub::DelegatedAdmin": {
                description:
                        "The ''AWS::SecurityHub::DelegatedAdmin'' resource designates the delegated ASHlong administrator account for an organization. You must enable the integration between ASH and AOlong before you can designate a delegated ASH administrator. Only the management account for an organization can designate the delegated ASH administrator account. For more information, see [Designating the delegated administrator](https://docs.aws.amazon.com/securityhub/latest/userguide/designate-orgs-admin-account.html#designate-admin-instructions) in the *User Guide*.\n To change the delegated administrator account, remove the current delegated administrator account, and then designate the new account.\n To designate multiple delegated administrators in different organizations and AWS-Regions, we recommend using [mappings](https://docs.aws.amazon.com/AWSCloudFormation/latest/UserGuide/mappings-section-structure.html).\n Tags aren't supported for this resource.",
                attributes: ["DelegatedAdminIdentifier", "Status"],
                properties: {
                        DelegatedAdminIdentifier: {
                                type: "string",
                                required: false,
                                description: "",
                        },
                        AdminAccountId: {
                                type: "string",
                                required: true,
                                description:
                                        "The AWS-account identifier of the account to designate as the Security Hub CSPM administrator account.",
                        },
                        Status: { type: "string", required: false, description: "" },
                },
        },
        "AWS::SecurityHub::FindingAggregator": {
                description:
                        "The ''AWS::SecurityHub::FindingAggregator'' resource enables cross-Region aggregation. When cross-Region aggregation is enabled, you can aggregate findings, finding updates, insights, control compliance statuses, and security scores from one or more linked Regions to a single aggregation Region. You can then view and manage all of this data from the aggregation Region. For more details about cross-Region aggregation, see [Cross-Region aggregation](https://docs.aws.amazon.com/securityhub/latest/userguide/finding-aggregation.html) in the *User Guide*\n This resource must be created in the Region that you want to designate as your aggregation Region.\n Cross-Region aggregation is also a prerequisite for using [central configuration](https://docs.aws.amazon.com/securityhub/latest/userguide/central-configuration-intro.html) in ASH.",
                attributes: ["FindingAggregatorArn", "FindingAggregationRegion"],
                properties: {
                        FindingAggregatorArn: {
                                type: "string",
                                required: false,
                                description: "",
                        },
                        RegionLinkingMode: {
                                type: "string",
                                required: true,
                                description:
                                        "Indicates whether to aggregate findings from all of the available Regions in the current partition. Also determines whether to automatically aggregate findings from new Regions as Security Hub supports them and you opt into them.\n The selected option also determines how to use the Regions provided in the Regions list.\n In CFN, the options for this property are as follows:\n  +  ''ALL_REGIONS'' - Indicates to aggregate findings from all of the Regions where Security Hub is enabled. When you choose this option, Security Hub also automatically aggregates findings from new Regions as Security Hub supports them and you opt into them. \n  +  ''ALL_REGIONS_EXCEPT_SPECIFIED'' - Indicates to aggregate findings from all of the Regions where Security Hub is enabled, except for the Regions listed in the ''Regions'' parameter. When you choose this option, Security Hub also automatically aggregates findings from new Regions as Security Hub supports them and you opt into them. \n  +  ''SPECIFIED_REGIONS'' - Indicates to aggregate findings only from the Regions listed in the ''Regions'' parameter. Security Hub does not automatically aggregate findings from new Regions.",
                        },
                        Regions: {
                                type: "array",
                                required: false,
                                description:
                                        "If ''RegionLinkingMode'' is ''ALL_REGIONS_EXCEPT_SPECIFIED'', then this is a space-separated list of Regions that do not aggregate findings to the aggregation Region.\n If ''RegionLinkingMode'' is ''SPECIFIED_REGIONS'', then this is a space-separated list of Regions that do aggregate findings to the aggregation Region.",
                        },
                        FindingAggregationRegion: {
                                type: "object",
                                required: false,
                                description: "",
                        },
                },
        },
        "AWS::SecurityHub::Hub": {
                description:
                        "The AWS::SecurityHub::Hub resource represents the implementation of the AWS Security Hub service in your account. One hub resource is created for each Region in which you enable Security Hub.\n\n",
                attributes: ["ARN", "SubscribedAt"],
                properties: {
                        ARN: {
                                type: "string",
                                required: false,
                                description:
                                        "An ARN is automatically created for the customer.",
                        },
                        EnableDefaultStandards: {
                                type: "boolean",
                                required: false,
                                description:
                                        "Whether to enable the security standards that Security Hub has designated as automatically enabled.",
                        },
                        ControlFindingGenerator: {
                                type: "string",
                                required: false,
                                description:
                                        "This field, used when enabling Security Hub, specifies whether the calling account has consolidated control findings turned on. If the value for this field is set to SECURITY_CONTROL, Security Hub generates a single finding for a control check even when the check applies to multiple enabled standards.  If the value for this field is set to STANDARD_CONTROL, Security Hub generates separate findings for a control check when the check applies to multiple enabled standards.",
                        },
                        AutoEnableControls: {
                                type: "boolean",
                                required: false,
                                description:
                                        "Whether to automatically enable new controls when they are added to standards that are enabled",
                        },
                        Tags: { type: "object", required: false, description: "" },
                        SubscribedAt: {
                                type: "string",
                                required: false,
                                description:
                                        "The date and time when Security Hub was enabled in the account.",
                        },
                },
        },
