        "AWS::Shield::Protection": {
                description:
                        "Enables AWS Shield Advanced for a specific AWS resource. The resource can be an Amazon CloudFront distribution, Amazon Route 53 hosted zone, AWS Global Accelerator standard accelerator, Elastic IP Address, Application Load Balancer, or a Classic Load Balancer. You can protect Amazon EC2 instances and Network Load Balancers by association with protected Amazon EC2 Elastic IP addresses.",
                attributes: ["ProtectionId", "ProtectionArn"],
                properties: {
                        ProtectionId: {
                                type: "string",
                                required: false,
                                description: "The unique identifier (ID) of the protection.",
                        },
                        ProtectionArn: {
                                type: "string",
                                required: false,
                                description:
                                        "The ARN (Amazon Resource Name) of the protection.",
                        },
                        Name: {
                                type: "string",
                                required: true,
                                description: "Friendly name for the Protection.",
                        },
                        ResourceArn: {
                                type: "string",
                                required: true,
                                description:
                                        "The ARN (Amazon Resource Name) of the resource to be protected.",
                        },
                        HealthCheckArns: {
                                type: "array",
                                required: false,
                                description:
                                        "The Amazon Resource Names (ARNs) of the health check to associate with the protection.",
                        },
                        ApplicationLayerAutomaticResponseConfiguration: {
                                type: "object",
                                required: false,
                                description: "",
                        },
                        Tags: {
                                type: "array",
                                required: false,
                                description:
                                        "One or more tag key-value pairs for the Protection object.",
                        },
                },
        },
        "AWS::Shield::ProtectionGroup": {
                description:
                        "A grouping of protected resources so they can be handled as a collective. This resource grouping improves the accuracy of detection and reduces false positives.",
                attributes: ["ProtectionGroupArn"],
                properties: {
                        ProtectionGroupId: {
                                type: "string",
                                required: true,
                                description:
                                        "The name of the protection group. You use this to identify the protection group in lists and to manage the protection group, for example to update, delete, or describe it.",
                        },
                        ProtectionGroupArn: {
                                type: "string",
                                required: false,
                                description:
                                        "The ARN (Amazon Resource Name) of the protection group.",
                        },
                        Aggregation: {
                                type: "string",
                                required: true,
                                description:
                                        "Defines how AWS Shield combines resource data for the group in order to detect, mitigate, and report events.\n* Sum - Use the total traffic across the group. This is a good choice for most cases. Examples include Elastic IP addresses for EC2 instances that scale manually or automatically.\n* Mean - Use the average of the traffic across the group. This is a good choice for resources that share traffic uniformly. Examples include accelerators and load balancers.\n* Max - Use the highest traffic from each resource. This is useful for resources that don't share traffic and for resources that share that traffic in a non-uniform way. Examples include Amazon CloudFront and origin resources for CloudFront distributions.",
                        },
                        Pattern: {
                                type: "string",
                                required: true,
                                description:
                                        "The criteria to use to choose the protected resources for inclusion in the group. You can include all resources that have protections, provide a list of resource Amazon Resource Names (ARNs), or include all resources of a specified resource type.",
                        },
                        Members: {
                                type: "array",
                                required: false,
                                description:
                                        "The Amazon Resource Names (ARNs) of the resources to include in the protection group. You must set this when you set 'Pattern' to 'ARBITRARY' and you must not set it for any other 'Pattern' setting.",
                        },
                        ResourceType: {
                                type: "string",
                                required: false,
                                description:
                                        "The resource type to include in the protection group. All protected resources of this type are included in the protection group. Newly protected resources of this type are automatically added to the group. You must set this when you set 'Pattern' to 'BY_RESOURCE_TYPE' and you must not set it for any other 'Pattern' setting.",
                        },
                        Tags: {
                                type: "array",
                                required: false,
                                description:
                                        "One or more tag key-value pairs for the Protection object.",
                        },
                },
        },
